// Renders the page from data/graph.json, regenerated by
// scripts/generate_site_data.py — nothing here is hand-authored per entity.

function el(tag, attrs, children) {
  const node = document.createElement(tag);
  if (attrs) {
    for (const key in attrs) {
      if (key === "class") node.className = attrs[key];
      else if (key === "html") node.innerHTML = attrs[key];
      else node.setAttribute(key, attrs[key]);
    }
  }
  (children || []).forEach((c) => node.appendChild(c));
  return node;
}

function wikidataLink(entity) {
  return el("a", {
    href: `https://www.wikidata.org/wiki/${entity.qid}`,
    target: "_blank",
    rel: "noopener",
    class: "mono",
  }, [document.createTextNode(entity.qid)]);
}

function renderStatusbar(data) {
  const el2 = document.getElementById("statusbar-meta");
  const when = new Date(data.generated_at).toLocaleString();
  el2.textContent = `${data.counts.entities} entities · ${data.counts.relations} relations · generated ${when}`;
}

function renderSubject(data) {
  const card = document.getElementById("subject-card");
  const s = data.subject;
  const initial = s.label.trim().charAt(0);

  const body = el("div", {}, [
    el("span", { class: "type-tag" }, [document.createTextNode(s.type)]),
    el("h3", {}, [document.createTextNode(s.label)]),
  ]);
  s.descriptions.forEach((d) => {
    body.appendChild(el("p", {}, [document.createTextNode(d)]));
  });
  body.appendChild(el("p", { class: "qid" }, [
    document.createTextNode("Wikidata: "),
    wikidataLink(s),
  ]));

  card.appendChild(el("div", { class: "badge" }, [document.createTextNode(initial)]));
  card.appendChild(body);
}

function entityCard(entity) {
  const card = el("div", { class: "entity-card" });
  card.dataset.type = entity.type;
  card.appendChild(el("span", { class: "type-tag" }, [document.createTextNode(entity.type)]));
  card.appendChild(el("h4", {}, [document.createTextNode(entity.label)]));
  if (entity.descriptions.length) {
    card.appendChild(el("p", {}, [document.createTextNode(entity.descriptions[0])]));
  }
  card.appendChild(el("p", {}, [document.createTextNode("Wikidata: "), wikidataLink(entity)]));
  return card;
}

function renderEntities(data) {
  const grid = document.getElementById("entity-grid");
  const filterBar = document.getElementById("entity-filters");

  const types = ["All", ...new Set(data.entities.map((e) => e.type))];
  types.forEach((type) => {
    const btn = el("button", {}, [document.createTextNode(type)]);
    if (type === "All") btn.classList.add("active");
    btn.addEventListener("click", () => {
      filterBar.querySelectorAll("button").forEach((b) => b.classList.remove("active"));
      btn.classList.add("active");
      grid.querySelectorAll(".entity-card").forEach((card) => {
        card.style.display = (type === "All" || card.dataset.type === type) ? "" : "none";
      });
    });
    filterBar.appendChild(btn);
  });

  data.entities.forEach((entity) => grid.appendChild(entityCard(entity)));
}

function renderBridgeEntities(data) {
  const list = document.getElementById("bridge-list");
  data.extra_entities.forEach((entity) => {
    const item = el("div", { class: "bridge-item" }, [
      el("span", { class: "type-tag" }, [document.createTextNode(entity.type)]),
      document.createTextNode(entity.label),
    ]);
    list.appendChild(item);
  });
}

function loadCodeBlock(elementId, path) {
  fetch(path)
    .then((response) => response.text())
    .then((text) => { document.getElementById(elementId).textContent = text; })
    .catch((err) => {
      document.getElementById(elementId).textContent = `could not load ${path}`;
      console.error(err);
    });
}

fetch("data/graph.json")
  .then((response) => response.json())
  .then((data) => {
    renderStatusbar(data);
    renderSubject(data);
    renderEntities(data);
    renderBridgeEntities(data);
  })
  .catch((err) => {
    document.getElementById("statusbar-meta").textContent =
      "could not load data/graph.json, run the pipeline first (python3 scripts/main.py)";
    console.error(err);
  });

loadCodeBlock("code-tei", "assets/tei_encoding.xml");
loadCodeBlock("code-script", "assets/tei_csv_to_rdf.py");
